import { and, cosineDistance, desc, eq, sql, gt } from "drizzle-orm";
import { createEmbedding, createEmbeddingMany } from "./embedding";
import { connectionsSchema, type TSelectUser } from "~/server/db/schema";
import { db } from "~/server/db";

export const searchSimilarConnections = async (
  query: string,
  user: TSelectUser,
) => {
  const {
    embeddings: [queryEmbedding, userEmbedding],
  } = await createEmbeddingMany([query, user.summary as string]);

  const querySimilarity = sql<number>`1 - (${cosineDistance(connectionsSchema.embedding, queryEmbedding!)})`;
  const userSimilarity = sql<number>`1 - (${cosineDistance(connectionsSchema.embedding, userEmbedding!)})`;
  const combinedScore = sql<number>`0.6 * ${querySimilarity!} + 0.4 * ${userSimilarity!}`; // bias towards query similarity

  return await db
    .select({
      company: connectionsSchema.company,
      linkedinURL: connectionsSchema.linkedinURL,
      name: connectionsSchema.name,
      position: connectionsSchema.position,
      connectedOn: connectionsSchema.connectedOn,
      summary: connectionsSchema.summary,
      userSummary: sql<string>`${user.summary}`,
      querySimilarity,
      userSimilarity,
      combinedScore,
    })
    .from(connectionsSchema)
    .where(eq(connectionsSchema.userID, user.id))
    .orderBy((t) => desc(t.combinedScore))
    .limit(4);
};
import { generateText, tool } from "ai";
import z from "zod";
import { searchSimilarConnections } from "../search";
import type { TSelectUser } from "~/server/db/schema";
import { model } from "../model";

export const makeSearchConnectionsTool = (user: TSelectUser) =>
  tool({
    args: { name: "search-connections" },
    description: "Search for relevant semantic profiles of user's connections",
    inputSchema: z.object({
      query: z.string().describe("The query to search connections for"),
    }),
    execute: async ({ query }) => {
      const connections = await searchSimilarConnections(query, user);

      const withReasons = await Promise.all(
        connections.map(async (res) => {
          const { text: reason } = await generateText({
            model,
            system: `You are an assistant that explains why a user's connection is relevant.`,
            prompt: `
User profile: ${res.userSummary}
Search query: ${query}
Connection profile:
  - Name: ${res.name}
  - Position: ${res.position} at ${res.company}
  - Summary: ${res.summary}

Scores:
  - Query similarity: ${res.querySimilarity}
  - User similarity: ${res.userSimilarity}

Concisely explain in 1-2 sentences why this connection matches, highlighting overlap with the query and/or user's background. Be clear and human-sounding.`,
          });

          return {
            ...res,
            reason,
          };
        }),
      );

      return withReasons;
    },
  });
import {
  convertToModelMessages,
  stepCountIs,
  streamText,
  type UIMessage,
} from "ai";
import type { NextRequest } from "next/server";
import { model } from "~/ai-core/model";
import { makeSearchConnectionsTool } from "~/ai-core/tools/search-connections";
import { db } from "~/server/db";
import { createClient } from "~/utils/supabase/server";

export async function POST(req: NextRequest) {
  const { messages }: { messages: UIMessage[] } = await req.json();
  const supabase = await createClient();
  const {
    data: { user },
    error,
  } = await supabase.auth.getUser();

  if (error || !user) throw new Error("UNAUTHORIZED");

  const dbUser = (await db.query.userSchema.findFirst({
    where: ({ id }, { eq }) => eq(id, user.id),
  }))!;

  const res = streamText({
    model,
    prompt: convertToModelMessages(messages),
    stopWhen: stepCountIs(5),
    system: `You are aeonik, a professional AI assistant specialized in helping users find relevant connections from their network and reconnect with them. 

Your job is to:
1. Search through semantic profiles of the user's connections.
2. Identify people who are most likely to be useful or relevant for the user's current context, query, or objective.
3. When suggesting connections, always provide a short explanation for *why* each person is recommended, based on shared industries, roles, locations, groups, or experience.
4. Present recommendations in a clear, friendly format, with each suggestion as a bullet point including:
5. After listing the suggested connections, include 1-2 sentences summarizing *why* they were chosen.
6. Be concise, professional, and avoid making assumptions beyond the data in the user's semantic profiles.
`,
    tools: { searchConnections: makeSearchConnectionsTool(dbUser) },
  });

  return res.toUIMessageStreamResponse();
}

